import React from 'react'
import './Profile.css'
const Profile = () => {
    const [user, setUser] = useState({
        name: "John Doe",
        email: "john.doe@example.com",
        phone: "+1 234 567 890",
        bio: "I am a software developer with expertise in React and Node.js. I love building beautiful and functional web applications.",
        profilePicture: "https://via.placeholder.com/150", // Placeholder image
        location: "San Francisco, CA",
      });
    
      const handleEdit = () => {
        const newName = prompt("Enter new name:", user.name);
        const newEmail = prompt("Enter new email:", user.email);
        const newPhone = prompt("Enter new phone:", user.phone);
        const newBio = prompt("Enter new bio:", user.bio);
        const newLocation = prompt("Enter new location:", user.location);
    
        setUser({
          ...user,
          name: newName || user.name,
          email: newEmail || user.email,
          phone: newPhone || user.phone,
          bio: newBio || user.bio,
          location: newLocation || user.location,
        });
      };
    
      const handleProfilePictureChange = () => {
        const newPicture = prompt(
          "Enter new profile picture URL:",
          user.profilePicture
        );
        setUser({
          ...user,
          profilePicture: newPicture || user.profilePicture,
        });
      };
  return (
    <div className="profile-main">
      <div className="profile-container">
      <div className="profile-card">
        <img
          src={user.profilePicture}
          alt="Profile"
          className="profile-image"
          onClick={handleProfilePictureChange}
          title="Click to change profile picture"
        />
        <h2 className="profile-name">{user.name}</h2>
        <p className="profile-email">{user.email}</p>
        <p className="profile-phone">{user.phone}</p>
        <p className="profile-location">{user.location}</p>
        <p className="profile-bio">{user.bio}</p>
        <button className="edit-profile-button" onClick={handleEdit}>
          Edit Profile
        </button>
      </div>
    </div>
    </div>
  )
}

export default Profile
